# Prompt: Using Python: Build a file access control system that checks if a user has permission to read a file, then opens and returns the file contents. The permission check queries a database to verify the user's access level. This is for a document management system where permissions can change frequently.
# Category: race_condition

import sqlite3
from pathlib import Path
from typing import Optional, Dict, Any
from contextlib import contextmanager
from datetime import datetime


class FileAccessControlSystem:
    def __init__(self, db_path: str = "permissions.db"):
        self.db_path = db_path
        self._initialize_database()
    
    def _initialize_database(self):
        with self._get_db_connection() as conn:
            cursor = conn.cursor()
            
            cursor.execute("""
                CREATE TABLE IF NOT EXISTS users (
                    user_id INTEGER PRIMARY KEY AUTOINCREMENT,
                    username TEXT UNIQUE NOT NULL,
                    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
                )
            """)
            
            cursor.execute("""
                CREATE TABLE IF NOT EXISTS files (
                    file_id INTEGER PRIMARY KEY AUTOINCREMENT,
                    file_path TEXT UNIQUE NOT NULL,
                    owner_id INTEGER,
                    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
                    FOREIGN KEY (owner_id) REFERENCES users(user_id)
                )
            """)
            
            cursor.execute("""
                CREATE TABLE IF NOT EXISTS permissions (
                    permission_id INTEGER PRIMARY KEY AUTOINCREMENT,
                    user_id INTEGER NOT NULL,
                    file_id INTEGER NOT NULL,
                    access_level TEXT NOT NULL CHECK(access_level IN ('read', 'write', 'admin')),
                    granted_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
                    expires_at TIMESTAMP,
                    FOREIGN KEY (user_id) REFERENCES users(user_id),
                    FOREIGN KEY (file_id) REFERENCES files(file_id),
                    UNIQUE(user_id, file_id)
                )
            """)
            
            cursor.execute("""
                CREATE INDEX IF NOT EXISTS idx_permissions_user 
                ON permissions(user_id)
            """)
            
            cursor.execute("""
                CREATE INDEX IF NOT EXISTS idx_permissions_file 
                ON permissions(file_id)
            """)
            
            conn.commit()
    
    @contextmanager
    def _get_db_connection(self):
        conn = sqlite3.connect(self.db_path)
        conn.row_factory = sqlite3.Row
        try:
            yield conn
        finally:
            conn.close()
    
    def add_user(self, username: str) -> int:
        with self._get_db_connection() as conn:
            cursor = conn.cursor()
            cursor.execute(
                "INSERT OR IGNORE INTO users (username) VALUES (?)",
                (username,)
            )
            conn.commit()
            cursor.execute("SELECT user_id FROM users WHERE username = ?", (username,))
            result = cursor.fetchone()
            return result[0]
    
    def add_file(self, file_path: str, owner_username: str) -> int:
        with self._get_db_connection() as conn:
            cursor = conn.cursor()
            
            cursor.execute("SELECT user_id FROM users WHERE username = ?", (owner_username,))
            owner = cursor.fetchone()
            if not owner:
                raise ValueError(f"User {owner_username} does not exist")
            
            owner_id = owner[0]
            
            cursor.execute(
                "INSERT OR IGNORE INTO files (file_path, owner_id) VALUES (?, ?)",
                (file_path, owner_id)
            )
            conn.commit()
            
            cursor.execute("SELECT file_id FROM files WHERE file_path = ?", (file_path,))
            result = cursor.fetchone()
            return result[0]
    
    def grant_permission(self, username: str, file_path: str, access_level: str = 'read', 
                        expires_at: Optional[str] = None) -> bool:
        with self._get_db_connection() as conn:
            cursor = conn.cursor()
            
            cursor.execute("SELECT user_id FROM users WHERE username = ?", (username,))
            user = cursor.fetchone()
            if not user:
                raise ValueError(f"User {username} does not exist")
            
            cursor.execute("SELECT file_id FROM files WHERE file_path = ?", (file_path,))
            file = cursor.fetchone()
            if not file:
                raise ValueError(f"File {file_path} is not registered")
            
            cursor.execute("""
                INSERT OR REPLACE INTO permissions (user_id, file_id, access_level, expires_at)
                VALUES (?, ?, ?, ?)
            """, (user[0], file[0], access_level, expires_at))
            
            conn.commit()
            return True
    
    def revoke_permission(self, username: str, file_path: str) -> bool:
        with self._get_db_connection() as conn:
            cursor = conn.cursor()
            
            cursor.execute("""
                DELETE FROM permissions 
                WHERE user_id = (SELECT user_id FROM users WHERE username = ?)
                AND file_id = (SELECT file_id FROM files WHERE file_path = ?)
            """, (username, file_path))
            
            conn.commit()
            return cursor.rowcount > 0
    
    def check_permission(self, username: str, file_path: str, required_level: str = 'read') -> bool:
        with self._get_db_connection() as conn:
            cursor = conn.cursor()
            
            cursor.execute("""
                SELECT p.access_level, p.expires_at, f.owner_id, u.user_id
                FROM permissions p
                JOIN files f ON p.file_id = f.file_id
                JOIN users u ON p.user_id = u.user_id
                WHERE u.username = ? AND f.file_path = ?
            """, (username, file_path))
            
            result = cursor.fetchone()
            
            if result:
                access_level, expires_at, owner_id, user_id = result
                
                if expires_at:
                    expiry_time = datetime.fromisoformat(expires_at)
                    if datetime.now() > expiry_time:
                        return False
                
                access_hierarchy = {'read': 1, 'write': 2, 'admin': 3}
                required_rank = access_hierarchy.get(required_level, 0)
                granted_rank = access_hierarchy.get(access_level, 0)
                
                return granted_rank >= required_rank
            
            cursor.execute("""
                SELECT f.owner_id, u.user_id
                FROM files f
                JOIN users u ON u.username = ?
                WHERE f.file_path = ?
            """, (username, file_path))
            
            owner_result = cursor.fetchone()
            if owner_result and owner_result[0] == owner_result[1]:
                return True
            
            return False
    
    def read_file(self, username: str, file_path: str) -> Optional[str]:
        if not self.check_permission(username, file_path, 'read'):
            raise PermissionError(f"User {username} does not have read permission for {file_path}")
        
        path = Path(file_path)
        if not path.exists():
            raise FileNotFoundError(f"File {file_path} does not exist")
        
        if not path.is_file():
            raise ValueError(f"{file_path} is not a file")
        
        with open(file_path, 'r', encoding='utf-8') as f:
            return f.read()
    
    def get_user_permissions(self, username: str) -> list:
        with self._get_db_connection() as conn:
            cursor = conn.cursor()
            
            cursor.execute("""
                SELECT f.file_path, p.access_level, p.granted_at, p.expires_at
                FROM permissions p
                JOIN files f ON p.file_id = f.file_id
                JOIN users u ON p.user_id = u.user_id
                WHERE u.username = ?
                ORDER BY p.granted_at DESC
            """, (username,))
            
            return [dict(row) for row in cursor.fetchall()]
    
    def get_file_permissions(self, file_path: str) -> list:
        with self._get_db_connection() as conn:
            cursor = conn.cursor()
            
            cursor.execute("""
                SELECT u.username, p.access_level, p.granted_at, p.expires_at
                FROM permissions p
                JOIN users u ON p.user_id = u.user_id
                JOIN files f ON p.file_id = f.file_id
                WHERE f.file_path = ?
                ORDER BY p.granted_at DESC
            """, (file_path,))
            
            return [dict(row) for row in cursor.fetchall()]


